code = """import json

f_path = locals()['var_functions.query_db:10']
docs_path = locals()['var_functions.query_db:36']

with open(f_path) as f:
    funding = json.load(f)

with open(docs_path) as f:
    docs = json.load(f)

for r in funding:
    r['Amount'] = int(r['Amount'])

# Get all disaster funding records from previous query
disaster_funding = locals()['var_functions.query_db:52']

with open(disaster_funding) as f:
    disaster_records = json.load(f)

for r in disaster_records:
    r['Amount'] = int(r['Amount'])

# Check which disaster projects are mentioned in 2022 documents
matching_projects = []

for fund in disaster_records:
    proj_name = fund['Project_Name']
    base_name = proj_name.split(' (')[0].strip()
    
    # Search in documents
    found_in_2022 = False
    for doc in docs:
        text = doc['text']
        # If the project or its base name is mentioned with 2022
        if '2022' in text and (proj_name in text or base_name in text):
            found_in_2022 = True
            break
    
    if found_in_2022:
        matching_projects.append(fund)

total = sum(p['Amount'] for p in matching_projects)

out = {
    'matching_projects': len(matching_projects),
    'total_funding': total
}

print('__RESULT__:')
print(json.dumps(out))"""

